#include<bits/stdc++.h>
using namespace std;
long long n,a[1000010],c[1000010],sum,ans,mid;
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        c[i]=c[i-1]+a[i];
    }
    sum=c[n]/n;
    for(long long i=1;i<=n;i++)
    {
        c[i]-=sum*i;
    }
    sort(c+1,c+1+n);
    mid=c[(n+1)/2];
    for(long long i=1;i<=n;i++)
    {
        ans+=abs(c[i]-mid);
    }
    printf("%lld",ans);
    return 0;
}
